package matrix

import (
	"testing"
)

func matFrom(data [][]float64) *Matrix {
	rows := len(data)
	cols := len(data[0])
	m := New(rows, cols)
	for i, row := range data {
		copy(m.Data[i], row)
	}
	return m
}

func TestMultiply(t *testing.T) {
	tests := []struct {
		name    string
		a, b    *Matrix
		want    [][]float64
		wantErr bool
	}{
		{
			name: "2x2 standard",
			a:    matFrom([][]float64{{1, 2}, {3, 4}}),
			b:    matFrom([][]float64{{5, 6}, {7, 8}}),
			want: [][]float64{{19, 22}, {43, 50}},
		},
		{
			name: "2x3 times 3x2",
			a:    matFrom([][]float64{{1, 2, 3}, {4, 5, 6}}),
			b:    matFrom([][]float64{{7, 8}, {9, 10}, {11, 12}}),
			want: [][]float64{{58, 64}, {139, 154}},
		},
		{
			name: "identity 2x2",
			a:    matFrom([][]float64{{3, 7}, {2, 5}}),
			b:    matFrom([][]float64{{1, 0}, {0, 1}}),
			want: [][]float64{{3, 7}, {2, 5}},
		},
		{
			name: "1x1 scalar",
			a:    matFrom([][]float64{{3}}),
			b:    matFrom([][]float64{{4}}),
			want: [][]float64{{12}},
		},
		{
			name:    "incompatible dimensions",
			a:       matFrom([][]float64{{1, 2}}),
			b:       matFrom([][]float64{{1, 2}}),
			wantErr: true,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			result, err := tc.a.Multiply(tc.b)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error but got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			for i, row := range tc.want {
				for j, val := range row {
					if result.Data[i][j] != val {
						t.Errorf("[%d][%d]: got %v, want %v", i, j, result.Data[i][j], val)
					}
				}
			}
		})
	}
}
